import numpy as np

# Common backbone idea: Evaluate potential next nodes based on a balance of distance criteria and dispersion metrics to distribute paths efficiently and avoid overcrowding.

# {Select the next node by giving priority to the node that optimizes the product of inverse distance to the current node and the sum of distances from all trucks, focusing on maximizing both proximity and overall network spread.}

def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    if len(unvisited_nodes) == 0:
        return depot_node if current_node != depot_node else None

    scores = []

    for node in unvisited_nodes:
        distance_to_current = distance_matrix[current_node, node]
        truck_distances = [distance_matrix[truck_node, node] for truck_node in truck_nodes]
        sum_distance_to_trucks = np.sum(truck_distances)

        if distance_to_current > 0:
            proximity_metric = 1.0 / distance_to_current
        else:
            proximity_metric = np.inf

        combined_metric = proximity_metric * sum_distance_to_trucks

        scores.append((combined_metric, node))

    scores.sort(reverse=True)
    best_score, next_node = scores[0]

    return next_node
